import { CheckboxGroup } from '@tale-ui/react/checkbox-group';
import { Checkbox } from '@tale-ui/react/checkbox';
import { Icon } from '@tale-ui/react/icon';
import { Check } from 'lucide-react';

export function CheckboxGroupForm() {
  return (
    <CheckboxGroup label="Notification Preferences">
      <Checkbox.Root value="email">
        <Checkbox.Indicator>
          <Icon icon={Check} size="sm" />
        </Checkbox.Indicator>
        Email
      </Checkbox.Root>
      <Checkbox.Root value="sms">
        <Checkbox.Indicator>
          <Icon icon={Check} size="sm" />
        </Checkbox.Indicator>
        SMS
      </Checkbox.Root>
      <Checkbox.Root value="push">
        <Checkbox.Indicator>
          <Icon icon={Check} size="sm" />
        </Checkbox.Indicator>
        Push Notifications
      </Checkbox.Root>
    </CheckboxGroup>
  );
}
